import sys

# Simulate excessive memory consumption by growing a list indefinitely
def simulate_memory_hoarding():
    memory_hog = []
    try:
        while True:
            memory_hog.append("x" * 1000000)  # Append a large string
    except MemoryError:
        print("MemoryError: System ran out of memory!")
        print(f"Final list size: {len(memory_hog)} entries")

simulate_memory_hoarding()
